CREATE TABLE counters (
    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    page_views BIGINT UNSIGNED NOT NULL DEFAULT 0,
    small_counter SMALLINT UNSIGNED NOT NULL DEFAULT 0,
    tiny_flag TINYINT UNSIGNED NOT NULL DEFAULT 0,
    medium_counter MEDIUMINT UNSIGNED NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
